360→    public int numStreamThreads(final StreamsConfig config) {
361→        final int configuredNumStreamThreads = config.getInt(StreamsConfig.NUM_STREAM_THREADS_CONFIG);
362→
363→        // If there are named topologies but some are empty, this indicates a bug in user code
364→        if (hasNamedTopologies()) {
365→            if (hasNoLocalTopology()) {
366→                log.error("Detected a named topology with no input topics, a named topology may not be empty.");
367→                throw new TopologyException("Topology has no stream threads and no global threads, " +
368→                                                "must subscribe to at least one source topic or pattern.");
369→            }
370→        } else {
371→            // If both the global and non-global topologies are empty, this indicates a bug in user code
372→            if (hasNoLocalTopology() && !hasGlobalTopology()) {
373→                log.error("Topology with no input topics will create no stream threads and no global thread.");
374→                throw new TopologyException("Topology has no stream threads and no global threads, " +
375→                                                "must subscribe to at least one source topic or global table.");
376→            }
377→        }
378→
379→        // Lastly we check for an empty non-global topology and override the threads to zero if set otherwise
380→        if (configuredNumStreamThreads != 0 && hasNoLocalTopology()) {
381→            log.info("Overriding number of StreamThreads to zero for global-only topology");
382→            return 0;
383→        }
384→
385→        return configuredNumStreamThreads;
386→    }
